import org.junit.jupiter.api.Test;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicLeetcode() {
        // "leetcode" = "leet" + "code"
        assertTrue(new Solution().wordBreak("leetcode", Arrays.asList("leet", "code")));
    }

    @Test
    void reusingWords() {
        // "applepenapple" = "apple" + "pen" + "apple" — reuses "apple"
        assertTrue(new Solution().wordBreak("applepenapple", Arrays.asList("apple", "pen")));
    }

    @Test
    void impossible() {
        // "catsandog" — no segmentation covers the trailing 'g'
        assertFalse(new Solution().wordBreak("catsandog", Arrays.asList("cats", "dog", "sand", "and", "cat")));
    }

    @Test
    void singleCharMatch() {
        assertTrue(new Solution().wordBreak("a", Arrays.asList("a")));
    }

    @Test
    void singleCharNoMatch() {
        assertFalse(new Solution().wordBreak("a", Arrays.asList("b")));
    }

    @Test
    void repeatedSingleCharWords() {
        // "aaaaaaa" with dict ["a","aaa"]: multiple valid segmentations exist
        assertTrue(new Solution().wordBreak("aaaaaaa", Arrays.asList("a", "aaa")));
    }

    @Test
    void backtrackingTrap() {
        // "aaab" with dict ["a","aa","aaa"]: DP must NOT backtrack — answer is false
        assertFalse(new Solution().wordBreak("aaab", Arrays.asList("a", "aa", "aaa")));
    }
}
